import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Simplest cases ---
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // --- Base premiums per item type ---
  it("single sword → premium 105 G (100 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 105 }] });
  });
  it.todo("single amulet → premium 65 G (60 base + 5 fee)");
  it.todo("single staff → premium 85 G (80 base + 5 fee)");
  it.todo("single potion → premium 45 G (40 base + 5 fee)");

  // --- Components and building blocks ---
  it.todo("2 runes → 50 G base premium (+5 fee = 55 G)");
  it.todo("3 runes → 60 G base premium (block applies, +5 fee = 65 G)");
  it.todo("4 runes → 100 G base premium (no block, +5 fee = 105 G)");
  it.todo("7 runes → 175 G base premium (one block + 4 singles, +5 fee = 180 G)");
  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types, +5 fee = 80 G)");
  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks, +5 fee = 125 G)");

  // --- Modifiers ---
  it.todo("cursed sword adds 50% risk surcharge (100 + 50 + 5 = 155 G)");
  it.todo("high-enchantment (≥5) sword adds 30% surcharge (100 + 30 + 5 = 135 G)");
  it.todo("sword with exactly enchantment 5 → high-enchantment applies (135 G)");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge (105 G)");
  it.todo("cursed sword with enchantment 5 → both surcharges apply (100 + 50 + 30 + 5 = 185 G)");
  it.todo("long-standing customer (≥2 years) gets 20% loyalty discount");
  it.todo("customer with exactly 2 years → loyalty discount applies");
  it.todo("first insurance carries 10% surcharge on policy base");
  it.todo("follow-up contract (after first) gets 15% discount");
  it.todo("processing fee of 5 G is added to every premium");

  // --- Rounding ---
  it.todo("premium rounded up in MHPCO favor (197.5 → 198 G)");
  it.todo("payout rounded down in MHPCO favor (350.5 → 350 G)");

  // --- Multi-item policies and modifier scope ---
  it.todo("policy with cursed sword + plain amulet → 210 G (cursed applies to sword's base only)");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword (steel, ench 3): 0 years, no prior → 165 G");
  it.todo("long-standing customer's second contract (cursed sword, ench 7, 3 years) → 160 G");

  // --- Claim processing: standard reimbursement ---
  it.todo("regular sword damage 500 G → payout 400 G (full minus 100 deductible)");
  it.todo("damage to rune (250 G insurance), damage 200 G → payout 100 G");

  // --- Claim: high enchantment clause ---
  it.todo("steel sword, ench 9, damage 1000 G → payout 400 G (50% then deductible)");

  // --- Claim: dragon material ---
  it.todo("dragon-material sword, ench 5, damage 800 G → payout 700 G (full, then deductible)");

  // --- Claim: enchantment + dragon combined ---
  it.todo("dragon-material sword, ench 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword, ench exactly 8, damage 1000 G → payout 400 G");

  // --- Deductible per damage event ---
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");

  // --- Multiple same-type items ---
  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("two-sword policy: dragon attack damages both → each treated as separate damage with own deductible");
  it.todo("claim with more damages of a type than policy covers → CLI rejects (non-zero exit)");

  // --- Cap exhaustion ---
  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword policy → cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes block → insurance sum 1750 G (block discount affects premium only)");
  it.todo("sword cap 2000 G, two claims of 1500 G each → first payout 1400 (cap 600), second payout 600 (cap 0)");

  // --- Error cases ---
  it.todo("quote with unknown item type → CLI exits non-zero, stderr error, no results");
  it.todo("claim references item not in policy → CLI exits non-zero with stderr");
  it.todo("claim with negative damage amount → CLI exits non-zero with stderr");
});

