export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

export interface ScenarioResult {
  results: { premium: number }[];
}

const PROCESSING_FEE = 5;

const BASE_PRICE_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const basePriceFor = (item: Item): number => BASE_PRICE_BY_TYPE[item.type];

const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PRICE = 60;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const sumBasePrices = (items: Item[]): number =>
  items.reduce((s, i) => s + basePriceFor(i), 0);

const groupByType = (items: Item[]): Map<string, Item[]> => {
  const map = new Map<string, Item[]>();
  for (const item of items) {
    const list = map.get(item.type) ?? [];
    list.push(item);
    map.set(item.type, list);
  }
  return map;
};

const priceForComponentGroup = (group: Item[]): number =>
  group.length === COMPONENT_BLOCK_SIZE
    ? COMPONENT_BLOCK_PRICE
    : sumBasePrices(group);

const componentsPremium = (components: Item[]): number =>
  Array.from(groupByType(components).values())
    .reduce((sum, group) => sum + priceForComponentGroup(group), 0);

const itemsBasePremium = (items: Item[]): number => {
  const components = items.filter(isComponent);
  const nonComponents = items.filter((i) => !isComponent(i));
  return sumBasePrices(nonComponents) + componentsPremium(components);
};

const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const perItemSurchargeRate = (item: Item): number =>
  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
  ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_RATE : 0);

const itemSurcharges = (items: Item[]): number =>
  items.reduce((sum, item) => sum + basePriceFor(item) * perItemSurchargeRate(item), 0);

const quotePremium = (step: QuoteStep): number => {
  const base = itemsBasePremium(step.items);
  const surcharges = itemSurcharges(step.items);
  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
  const total = base + surcharges + firstInsuranceSurcharge + PROCESSING_FEE;
  return Math.ceil(total);
};

export const runScenario = (scenario: Scenario): ScenarioResult => ({
  results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
});

import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Simplest cases ---
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // --- Base premiums per item type ---
  it("single sword → premium 115 G (100 base + 10 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("single amulet → premium 71 G (60 base + 6 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("single staff → premium 93 G (80 base + 8 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("single potion → premium 49 G (40 base + 4 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // --- Components and building blocks ---
  it("2 runes → 50 G base, +5 first-ins +5 fee = 60 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes → 60 G base (block), +6 first-ins +5 fee = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("4 runes → 100 G base (no block), +10 first-ins +5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes → 175 G base (no block: count != 3), +17.5 first-ins +5 fee → 198 G (rounded up)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: Array.from({ length: 7 }, () => ({ type: "rune" })),
      }],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });
  it("2 runes + 1 moonstone → 75 G base (no block: different types), +7.5 first-ins +5 fee = 88 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("3 runes + 3 moonstones → 120 G base (two blocks), +12 first-ins +5 fee = 137 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [
          { type: "rune" }, { type: "rune" }, { type: "rune" },
          { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
        ],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // --- Modifiers ---
  it("cursed sword adds 50% risk surcharge (100 base + 50 curse = 150 + 5 fee = 155 G, no first-insurance test variant)", () => {
    // Test isolation: customer has prior contract so no first-insurance applies, but follow-up discount kicks in.
    // To isolate cursed only, we need a scenario where first-insurance and follow-up cancel/don't apply.
    // Simplest: use a customer where no other modifiers apply. Per spec "first insurance" is per-item-always.
    // Therefore: cursed sword in isolation = 100 base + 50 curse = 150, +10% first insurance = 165, no other discount, +5 fee = 170.
    // But the cleanest cursed-isolation expected by spec: a cursed sword alone for a new customer yields 165 G (per integration example).
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true }] }],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("sword ench 5 → high-ench surcharge (100+30+10+5=145 G)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
