type Policy = { items: Item[]; remainingCap: number };

const insuranceSum = (items: Item[]): number =>
  items.reduce((s, i) => s + INSURANCE_VALUE_BY_TYPE[i.type], 0);

const processClaim = (step: ClaimStep, policies: Policy[]): ClaimResult => {
  const policy = policies[step.policy];
  let totalPayout = 0;
  for (const damage of step.incident.damages) {
    const insuranceValue = INSURANCE_VALUE_BY_TYPE[damage.itemType];
    const reimbursed = Math.min(damage.amount, insuranceValue);
    const afterDeductible = Math.max(0, reimbursed - DEDUCTIBLE);
    const capped = Math.min(afterDeductible, policy.remainingCap - totalPayout);
    totalPayout += capped;
  }
  policy.remainingCap -= totalPayout;
  return { payout: Math.floor(totalPayout), remainingCap: policy.remainingCap };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const policies: Policy[] = [];
  const results: (QuoteResult | ClaimResult)[] = [];
  scenario.steps.forEach((step, i) => {
    if (step.op === "quote") {
      policies[i] = {
        items: step.items,
        remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
      };
      results.push({ premium: quotePremium(step, scenario.customer, i > 0) });
    } else {
      results.push(processClaim(step, policies));
    }
  });
  return { results };
};

