151	  return Math.max(0, insured - DEDUCTIBLE);
152	};
153	
154	const findPolicyItem = (items: Item[], itemType: string): Item =>
155	  items.find((i) => i.type === itemType)!;
156	
157	const totalPayoutWithinCap = (damages: Damage[], items: Item[], cap: number): number =>
158	  damages.reduce(
159	    (paid, damage) =>
160	      paid + Math.min(reimbursableFor(damage, findPolicyItem(items, damage.itemType)), cap - paid),
161	    0,
162	  );
163	
164	const processClaim = (step: ClaimStep, policies: Policy[]): ClaimResult => {
165	  const policy = policies[step.policy];
166	  const payout = totalPayoutWithinCap(step.incident.damages, policy.items, policy.remainingCap);
167	  policy.remainingCap -= payout;
168	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
169	};
170	
171	export const runScenario = (scenario: Scenario): ScenarioResult => {
172	  const policies: Policy[] = [];
173	  const results: (QuoteResult | ClaimResult)[] = [];
174	  scenario.steps.forEach((step, i) => {
175	    if (step.op === "quote") {
176	      policies[i] = {
177	        items: step.items,
178	        remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
179	      };
180	      results.push({ premium: quotePremium(step, scenario.customer, i > 0) });
181	    } else {
182	      results.push(processClaim(step, policies));
183	    }
184	  });
185	  return { results };
186	};

