175	const assertNonNegativeDamages = (damages: Damage[]): void => {
176	  const negative = damages.find((d) => d.amount < 0);
177	  if (negative) throw new Error(`Negative damage amount: ${negative.amount}`);
178	};
179	
180	const assertDamagesCoveredByPolicy = (damages: Damage[], items: Item[]): void => {
181	  const itemCounts = countByKey(items, (i) => i.type);
182	  const damageCounts = countByKey(damages, (d) => d.itemType);
183	  for (const [type, count] of damageCounts) {
184	    if (count > (itemCounts.get(type) ?? 0)) {
185	      throw new Error(`More ${type} damages than policy covers`);
186	    }
187	  }
188	};
189	
190	const processClaim = (step: ClaimStep, policies: Policy[]): ClaimResult => {
191	  assertNonNegativeDamages(step.incident.damages);
192	  const policy = policies[step.policy];
193	  assertDamagesCoveredByPolicy(step.incident.damages, policy.items);
194	  const payout = totalPayoutWithinCap(step.incident.damages, policy.items, policy.remainingCap);
195	  policy.remainingCap -= payout;
196	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
197	};
198	
199	const openPolicy = (items: Item[]): Policy => ({
200	  items,
201	  remainingCap: insuranceSum(items) * CAP_MULTIPLIER,
202	});
203	
204	export const runScenario = (scenario: Scenario): ScenarioResult => {
205	  const policies: Policy[] = [];
206	  const results: (QuoteResult | ClaimResult)[] = [];
207	  scenario.steps.forEach((step, stepIndex) => {
208	    if (step.op === "quote") {
209	      const isFollowUp = stepIndex > 0;
210	      policies[stepIndex] = openPolicy(step.items);
211	      results.push({ premium: quotePremium(step, scenario.customer, isFollowUp) });
212	    } else {
213	      results.push(processClaim(step, policies));
214	    }
215	  });
216	  return { results };
217	};

